  printf("%.12Lf\n", res);

  return 0;

}



long long solve() {

  memset(f, 0, sizeof(f));

  f[n * l[n]][0] = 1;

  for (int i = 0; i < n * c; ++i) {

    if (!(i % n)) continue;

