#include <iostream>





struct Answer {

    int yen_10000;

    int yen_5000;

    int yen_1000;



    bool is_valid() { 

        return yen_10000 != -1;

    }



    void print() {

        std::printf(

            "%d %d %d\n",

            yen_10000, yen_5000, yen_1000

        );

    }

};



struct Cond {

    bool use_10000 = true;

    bool use_5000  = true;

    bool use_1000  = true;

};





// n枚で1000*y円作る組み合わせを返す

Answer solve(const int n, const int ky, Cond cond) {

    //

    if(n == 0 && ky == 0) {

        return {0, 0, 0};

    }

    if(ky == 0) {

        return {-1, -1, -1};

    }

    if(ky == n) {

        return {0, 0, n};

    }



    //

    if(cond.use_10000) {

        for(int num = ky / 10; num >= 0; --num) {

            auto ans = solve(

                n - num, ky - num*10,

                {false, cond.use_5000, cond.use_1000}

            );

            if(ans.is_valid()) {

                ans.yen_10000 += num;

                return ans;

            }

        }

    }

    if(cond.use_5000) {

        for(int num = ky / 5; num >= 0; --num) {

            auto ans = solve(

                n - num, ky - num*5,

                {cond.use_10000, false, cond.use_1000}

            );

            if(ans.is_valid()) {

                ans.yen_5000 += num;

                return ans;

            }

        }

    }



    return {-1, -1, -1};

}



int main(void) {

    int N, Y;

    std::cin >> N >> Y;



    solve(N, Y/1000, {}).print();

